            'hero.title2': 'i domy modułowe',
            'hero.sub': 'Od kontenerów na przestrzenie wspólne po pełnowymiarowe domy modułowe — realizujemy zrównoważone, szybkie rozwiązania do życia i użytku społecznego.',
            'hero.cta': 'Zobacz projekty',
